  ('pukao-c5fb3965-moex-00097', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-114-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '為防發生難以回復之損害，對於無效行政處分為暫時權利保護之聲請時，應聲請法院為下列何種措施？', '["假扣押", "假處分", "假執行", "停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00098', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-114-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於損失補償之敘述，下列何者錯誤？', '["須為違法行為", "騎樓禁止擺攤位不構成特別犧牲", "人民因機關即時強制致財產損失，得請求補償", "須基於公益之必要性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00099', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-114-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '依國家賠償法規定，下列何種情形並不成立國家賠償責任？', '["職司道路養護之公務員故意怠於履行職務，長期無視道路特定坑洞之存在，致使機車騎士行經該路段滑 倒受傷", "員警進行夜間定時巡邏業務，因過失未留意燈號變換而誤闖紅燈，撞上依燈號指示左轉之民眾車輛", "因過去已有多起溺水意外，主管機關於開放水域設置禁止游泳之警示標語，人民仍執意下水而喪失生命", "高速公路交流道設計與建造有所缺失，匝道彎度明顯過大，導致民眾車輛翻覆而駕駛受傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00100', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-114-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '有關國家賠償之書面協議先行程序，下列敘述何者錯誤？', '["請求損害賠償時，於協議程序進行中，法院得依聲請為假處分，命賠償義務機關先行賠償損害", "請求損害賠償時，應先以書面向賠償義務機關請求之", "協議成立時，應作成協議書，該項協議書得為執行名義", "賠償義務機關拒絕賠償，請求權人得提起損害賠償之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:38+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00101', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-113-4dccc0e6', 'sub-pukao-c5fb3965-01', NULL, 'single_choice', '政府部門為了避免決策或資源分配時過度偏袒特定的族群或團體，應從人口或地域等多元面向來考慮行政 機關的人力結構，以求充分反映各個階層的利益或意見。下列那一個概念與此一主張最為相近？', '["審議式民主", "代表性官僚", "代議式民主", "行政中立化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "911a7b7a5265", "answer_pdf_sha1": "4139af4fbb5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00102', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-113-4dccc0e6', 'sub-pukao-c5fb3965-01', NULL, 'single_choice', '針對公共行政中所追求的效率，下列何者錯誤？', '["效率是公共行政領域中最早被強調的價值", "效率指的是產出與投入的比例", "效率指的是投入資源所產生的影響", "政府對效率的注重，最早是建立在科學管理的基礎上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "911a7b7a5265", "answer_pdf_sha1": "4139af4fbb5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00103', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-113-4dccc0e6', 'sub-pukao-c5fb3965-01', NULL, 'single_choice', '有關黑堡宣言之敘述，下列何者正確？', '["認為公共利益的意涵有明確的定義", "公共行政應多師法企業，採用私部門的管理方式以提升效率", "行政人員應可成為自我意識的公共利益受託者", "司法與立法有所衝突時，公共行政將受制於前述兩者而應妥協"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "911a7b7a5265", "answer_pdf_sha1": "4139af4fbb5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL)
